#!/usr/bin/env bashset -euo pipefailif [ -z "${POSTGRES_HOST:-}" ] || [ -z "${POSTGRES_DB:-}" ] || [ -z "${POSTGRES_USER:-}" ] || [ -z "${POSTGRES_PASSWORD:-}" ]; then  echo "POSTGRES_HOST, POSTGRES_DB, POSTGRES_USER, and POSTGRES_PASSWORD must all be set."  exit 1fiexport PGPASSWORD="${POSTGRES_PASSWORD}"echo "Waiting for PostgreSQL at ${POSTGRES_HOST}:${POSTGRES_PORT:-5432}..."until pg_isready -h "$POSTGRES_HOST" -U "$POSTGRES_USER" -d "$POSTGRES_DB"; do  sleep 5doneif [ ! -d "/sql" ]; then  echo "SQL directory /sql is missing."  exit 1fiecho "Running SQL initialization scripts..."for sql_file in $(find /sql -maxdepth 1 -type f -name '*.sql' | sort); do  sql_name=$(basename "$sql_file")  case "$sql_name" in    --*|15_rollback_dev.sql)      echo "Skipping $sql_name"      continue      ;;  esac  echo "Running $sql_file"  psql -h "$POSTGRES_HOST" -U "$POSTGRES_USER" -d "$POSTGRES_DB" -f "$sql_file"doneecho "Database initialization completed."